Looking at the requirements and the provided code structure, I need to implement three functions. Here's the complete implementation:

```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {

  // Connect to database and insert records
  auto result = sqlgen::sqlite::connect(db_path)
      .and_then([&](auto&& conn) {
        return sqlgen::insert(conn, records);
      });

  if (!result) {
    throw std::runtime_error("Failed to insert records into table: " + table_name);
  }
}

template<typename NewValueType>
void modify_eas_records_by_id(const std::string& table_name,
                              int record_id,
                              const std::string& col_name,
                              NewValueType new_value) {

  // Create a mapping of table names to their primary key column names
  static const std::map<std::string, std::string> table_primary_keys = {
    {"Student", "SNo"},
    {"Course", "CID"},
    {"Score", "ScID"},
    {"Major", "MID"}
  };

  auto it = table_primary_keys.find(table_name);
  if (it == table_primary_keys.end()) {
    throw std::runtime_error("Unknown table: " + table_name);
  }

  const std::string& primary_key = it->second;

  // Build and execute the update query
  std::string sql = "UPDATE " + table_name + " SET " + col_name + " = ? WHERE " + primary_key + " = ?";

  auto result = sqlgen::sqlite::connect(db_path)
      .and_then([&](auto&& conn) {
        return sqlgen::exec(conn, sql, new_value, record_id);
      });

  if (!result) {
    throw std::runtime_error("Failed to modify record in table: " + table_name);
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {

  // Create a mapping of table names to their primary key column names
  static const std::map<std::string, std::string> table_primary_keys = {
    {"Student", "SNo"},
    {"Course", "CID"},
    {"Score", "ScID"},
    {"Major", "MID"}
  };

  auto it = table_primary_keys.find(table_name);
  if (it == table_primary_keys.end()) {
    throw std::runtime_error("Unknown table: " + table_name);
  }

  const std::string& primary_key = it->second;

  // Build and execute the delete query
  std::string sql = "DELETE FROM " + table_name + " WHERE " + primary_key + " = ?";

  auto result = sqlgen::sqlite::connect(db_path)
      .and_then([&](auto&& conn) {
        return sqlgen::exec(conn, sql, record_id);
      });

  if (!result) {
    throw std::runtime_error("Failed to delete record from table: " + table_name);
  }
}
```

**Key implementation details:**

1. **`add_eas_records`**: Uses `sqlgen::insert` to insert a vector of records. The template parameter `T` must match the table structure.

2. **`modify_eas_records_by_id`**: 
   - Made it a template function to handle different `new_value` types
   - Uses a mapping to determine the correct primary key column for each table
   - Builds and executes a parameterized SQL UPDATE statement

3. **`delete_eas_records_by_id`**:
   - Uses the same table-to-primary-key mapping
   - Builds and executes a parameterized SQL DELETE statement
   - Takes `record_id` as `std::string` to handle both string (Student.SNo) and integer primary keys

4. **Error handling**: All functions throw `std::runtime_error` if database operations fail.

**Usage examples:**
```cpp
// Add students
std::vector<Student> students = {
  {"20230001", "John Doe", 1, std::nullopt, 1, 85.5, std::nullopt},
  {"20230002", "Jane Smith", 0, std::nullopt, 1, 92.0, "Excellent"}
};
add_eas_records("Student", students);

// Modify a course's credit
modify_eas_records_by_id("Course", 101, "Credit", 3);

// Delete a student
delete_eas_records_by_id("Student", "20230001");
```

The implementation follows the `sqlgen` library patterns and provides type-safe operations while handling the different primary key types across tables.

