```cpp
#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace batch_insert_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  float price;
  std::string category;
  int stock;
};

/**
 * Function: Perform efficient batch insertion of product data using a transaction.
 * 
 * @param products List of products to insert
 * @return true if all inserts succeed, false otherwise
 */
bool batch_insert_products(const std::vector<Product>& products) {
    try {
        // Connect to SQLite database
        sqlgen::SQLite db("test_db.sqlite");

        // Drop table if exists
        db.execute("DROP TABLE IF EXISTS Product");

        // Create Product table
        db.execute(R"(
            CREATE TABLE Product (
                product_id INTEGER PRIMARY KEY,
                name VARCHAR(100) NOT NULL,
                price REAL NOT NULL,
                category VARCHAR(50) NOT NULL,
                stock INTEGER NOT NULL DEFAULT 0
            )
        )");

        // Begin transaction
        db.beginTransaction();

        try {
            // Insert all products
            for (const auto& product : products) {
                db.insert(product);
            }

            // Commit transaction if all inserts succeed
            db.commitTransaction();
            return true;

        } catch (const std::exception& e) {
            // Rollback transaction if any insert fails
            db.rollbackTransaction();
            return false;
        }

    } catch (const std::exception& e) {
        // Return false if database connection or table creation fails
        return false;
    }
}

}  // namespace batch_insert_products
```

