```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::optional<std::string> city;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

struct MutualFriendsResult {
  std::string user1_name;
  std::string user2_name;
  int mutual_friends_count;
};

struct FriendCountResult {
  std::string username;
  int friend_count;
};

struct UserConnection {
  std::string user1_name;
  std::string user2_name;
  std::string connection_type;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
    // Create in-memory SQLite database
    sqlgen::SQLiteDB db(":memory:");

    // Create User table
    auto user_table = sqlgen::Table<User>("User", 
        &User::user_id, 
        &User::username, 
        &User::email, 
        &User::join_date, 
        &User::city);

    // Create Friendship table
    auto friendship_table = sqlgen::Table<Friendship>("Friendship", 
        &Friendship::user1_id, 
        &Friendship::user2_id, 
        &Friendship::created_at);

    // Create tables in database
    db.create_table(user_table);
    db.create_table(friendship_table);

    // Insert users and friendships
    for (const auto& user : users) {
        db.insert(user_table, user);
    }
    for (const auto& friendship : friendships) {
        db.insert(friendship_table, friendship);
    }

    std::vector<FriendConnection> results;

    // 1. Use SELF-JOIN to find mutual friends (friends who share the same friend)
    auto mutual_friends = db.execute_query<MutualFriendsResult>(
        "SELECT u1.username AS user1_name, u2.username AS user2_name, COUNT(f1.user1_id) AS mutual_friends_count "
        "FROM User u1 "
        "INNER JOIN Friendship f1 ON u1.user_id = f1.user1_id "
        "INNER JOIN Friendship f2 ON f1.user2_id = f2.user1_id "
        "INNER JOIN User u2 ON f2.user2_id = u2.user_id "
        "WHERE u1.user_id < u2.user_id "
        "  AND EXISTS ("
        "    SELECT 1 FROM Friendship f3 "
        "    WHERE f3.user1_id = u1.user_id AND f3.user2_id = u2.user_id"
        "  ) "
        "GROUP BY u1.user_id, u2.user_id "
        "HAVING COUNT(f1.user2_id) > 0"
    );

    // 2. Use nested query to find users with more than average friends
    auto popular_users = db.execute_query<FriendCountResult>(
        "SELECT u.username, COUNT(f.user2_id) AS friend_count "
        "FROM User u "
        "LEFT JOIN Friendship f ON u.user_id = f.user1_id "
        "GROUP BY u.user_id, u.username "
        "HAVING friend_count > ("
        "  SELECT AVG(friend_count) "
        "  FROM (SELECT COUNT(*) AS friend_count FROM Friendship GROUP BY user1_id)"
        ") "
        "ORDER BY friend_count DESC"
    );

    // 3. Find friend-of-friend relationships (people connected through exactly one mutual friend)
    auto fof_connections = db.execute_query<FriendConnection>(
        "SELECT u1.username AS user1_name, u3.username AS user2_name "
        "FROM User u1 "
        "JOIN Friendship f1 ON u1.user_id = f1.user1_id "
        "JOIN User u2 ON f1.user2_id = u2.user_id "
        "JOIN Friendship f2 ON u2.user_id = f2.user1_id "
        "JOIN User u3 ON f2.user2_id = u3.user_id "
        "WHERE u1.user_id != u3.user_id "
        "  AND NOT EXISTS ("
        "    SELECT 1 FROM Friendship f3 "
        "    WHERE f3.user1_id = u1.user_id AND f3.user2_id = u3.user_id"
        "  )"
    );

    // 4. Count friends per user and identify most connected users
    auto friend_counts = db.execute_query<FriendCountResult>(
        "SELECT u.username, COUNT(f.user2_id) AS friend_count "
        "FROM User u "
        "LEFT JOIN Friendship f ON u.user_id = f.user1_id "
        "GROUP BY u.user_id, u.username "
        "ORDER BY friend_count DESC"
    );

    // 5. Find users in the same city who are not yet friends (recommendation)
    auto city_recommendations = db.execute_query<FriendConnection>(
        "SELECT u1.username AS user1_name, u2.username AS user2_name "
        "FROM User u1 "
        "JOIN User u2 ON u1.city = u2.city AND u1.user_id < u2.user_id "
        "WHERE u1.city IS NOT NULL "
        "  AND NOT EXISTS ("
        "    SELECT 1 FROM Friendship f "
        "    WHERE (f.user1_id = u1.user_id AND f.user2_id = u2.user_id) "
        "       OR (f.user1_id = u2.user_id AND f.user2_id = u1.user_id)"
        "  )"
    );

    // Combine results from different analyses
    for (const auto& conn : fof_connections) {
        results.push_back(conn);
    }

    // Also add mutual friends connections
    for (const auto& mutual : mutual_friends) {
        if (mutual.mutual_friends_count > 0) {
            FriendConnection conn{mutual.user1_name, mutual.user2_name};
            results.push_back(conn);
        }
    }

    // Add city-based recommendations
    for (const auto& rec : city_recommendations) {
        results.push_back(rec);
    }

    return results;
}

}  // namespace analyze_social_network
```

