std::vector<UpdatedNote> replace_text_in_notes() {
  // Connect to SQLite database
  sqlgen::SQLiteDB db("test_db.sqlite");

  // Create table access object
  auto notes_table = db.table<Note>("Notes");

  // Update all notes by replacing "foo" with "bar" in content
  notes_table.update_all([](Note& note) {
    // Replace all occurrences of "foo" with "bar"
    size_t pos = 0;
    while ((pos = note.content.find("foo", pos)) != std::string::npos) {
      note.content.replace(pos, 3, "bar");
      pos += 3; // Move past the replacement
    }
  });

  // Retrieve updated notes for verification
  auto updated_notes = notes_table.select_all();

  // Convert to UpdatedNote format for return
  std::vector<UpdatedNote> result;
  for (const auto& note : updated_notes) {
    result.push_back(UpdatedNote{
      .note_id = note.note_id,
      .updated_content = note.content
    });
  }

  return result;
}

}  // namespace replace_text_in_notes
