    auto update_stmt = db.prepare<Account>(
      sqlgen::update<Account>()
        .set(&Account::balance, 1500.0)
        .set(&Account::status, "updated")
        .where(sqlgen::eq(&Account::account_id, 1))
    );
    update_stmt.execute();

    // Update multiple accounts with different values using set
    auto update_stmt2 = db.prepare<Account>(
      sqlgen::update<Account>()
        .set(&Account::balance, 3000.0)
        .set(&Account::status, "premium")
        .where(sqlgen::eq(&Account::account_id, 2))
    );
    update_stmt2.execute();

    // Update with conditional set based on current value
    auto update_stmt3 = db.prepare<Account>(
      sqlgen::update<Account>()
