 */
std::vector<SupProd> full_join_suppliers_products() {
  // Create database connection
  auto db = sqlgen::database<sqlgen::sqlite>("test_db.sqlite");

  // Since SQLite doesn't natively support FULL JOIN, we simulate it using UNION of LEFT and RIGHT JOIN
  // First part: LEFT JOIN (all suppliers with their products)
  auto left_join = db.select(
    sqlgen::columns(&Supplier::name, &Product::name),
    sqlgen::left_join<Product>(&Supplier::supplier_id, &Product::supplier_id)
  );

  // Second part: RIGHT JOIN simulation using LEFT JOIN with tables swapped
  // and filtering out records that already exist in the first part
  auto right_join = db.select(
    sqlgen::columns(&Supplier::name, &Product::name),
    sqlgen::left_join<Supplier>(&Product::supplier_id, &Supplier::supplier_id)
  ).where(sqlgen::is_null(&Supplier::supplier_id));

  // Combine results using UNION (simulating FULL JOIN)
  std::vector<SupProd> results;

  // Process left join results
  for (const auto& row : left_join) {
    SupProd item;
    item.supplier_name = std::get<0>(row);
    if (std::get<1>(row).has_value()) {
      item.product_name = std::get<1>(row).value();
    }
