    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Employee e
    LEFT JOIN Department d ON e.department_id = d.department_id
  )");

  left_join_stmt.query([&analysis](std::optional<std::string> department_name, 
                                  std::string first_name, std::string last_name, double salary) {
    analysis.left_join_results.push_back(JoinResult{
      department_name, first_name, last_name, salary
    });
    return true;
  });

  // 3. RIGHT JOIN - All departments (even without employees)
  // SQLite doesn't natively support RIGHT JOIN, so we emulate it with LEFT JOIN
  auto right_join_stmt = conn.prepare(R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Department d
    LEFT JOIN Employee e ON d.department_id = e.department_id
    WHERE e.employee_id IS NULL OR e.employee_id IS NOT NULL
  )");

  right_join_stmt.query([&analysis](std::string department_name, 
                                   std::optional<std::string> first_name, 
                                   std::optional<std::string> last_name, 
                                   std::optional<double> salary) {
    analysis.right_join_results.push_back(JoinResult{
      department_name, first_name, last_name, salary
    });
    return true;
  });

  // 4. FULL JOIN - All employees and departments
  // SQLite doesn't natively support FULL JOIN, so we emulate it with UNION of LEFT and RIGHT joins
  auto full_join_stmt = conn.prepare(R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Employee e
    LEFT JOIN Department d ON e.department_id = d.department_id
    UNION
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Department d
    LEFT JOIN Employee e ON d.department_id = e.department_id
  )");

  full_join_stmt.query([&analysis](std::optional<std::string> department_name, 
                                  std::optional<std::string> first_name, 
                                  std::optional<std::string> last_name, 
                                  std::optional<double> salary) {
    analysis.full_join_results.push_back(JoinResult{
      department_name, first_name, last_name, salary
    });
    return true;
  });

  return analysis;
}

}  // namespace analyze_department_employees
